# Generated by openai (o1)
# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'REGISTRY_URL', defaultValue: 'myregistry.com', description: 'Docker registry URL')
        string(name: 'IMAGE_NAME', defaultValue: 'myapp', description: 'Name of Docker image')
        string(name: 'IMAGE_TAG', defaultValue: 'latest', description: 'Tag for Docker image')
    }

    stages {
        stage('Build') {
            steps {
                sh "docker build -t ${params.REGISTRY_URL}/${params.IMAGE_NAME}:${params.IMAGE_TAG} ."
            }
        }
        stage('Push') {
            steps {
                sh "docker push ${params.REGISTRY_URL}/${params.IMAGE_NAME}:${params.IMAGE_TAG}"
            }
        }
    }
}